import sys

def first_occurrence(arr, target):
    l, r = 0, len(arr) - 1
    while l <= r:
        m = (l + r) // 2
        if arr[m] >= target:
            r = m - 1
        else:
            l = m + 1
    return l

def last_occurrence(arr, target):
    l, r = 0, len(arr) - 1
    while l <= r:
        m = (l + r) // 2
        if arr[m] <= target:
            l = m + 1
        else:
            r = m - 1
    return r

def solve():
    data = sys.stdin.read().strip().split()
    T = int(data[0])
    idx = 1
    for _ in range(T):
        n = int(data[idx])
        idx += 1
        arr = list(map(int, data[idx:idx+n]))
        idx += n
        target = int(data[idx])
        idx += 1
        first = first_occurrence(arr, target)
        if first >= n or arr[first] != target:
            print(0)
        else:
            last = last_occurrence(arr, target)
            print(last - first + 1)

if __name__ == "__main__":
    solve()

